function validateUserOp(PackedUserOperation calldata uo, bytes32 h, uint256 missingFunds)
    external returns (uint256 vd)
{
    require(msg.sender == entryPoint());
    bool ok = SignatureCheckerLib.isValidSignatureNowCalldata(
        owner(), toEthSignedMessageHash(h), uo.signature
    );
    vd = ok ? 0 : 1;
    if (missingFunds > 0) {
        (bool s, ) = msg.sender.call{value: missingFunds}("");
        require(s);
    }
}

yul_optimized:
function validateUserOp(PackedUserOperation calldata userOp, bytes32 userOpHash, uint256 missingAccountFunds)
    external payable virtual onlyEntryPoint payPrefund(missingAccountFunds)
    returns (uint256 validationData)
{
    validationData = _validateSignature(userOp, userOpHash);
    _validateNonce(userOp.nonce);
}

function _validateSignature(PackedUserOperation calldata userOp, bytes32 userOpHash)
    internal virtual returns (uint256 validationData)
{
    bool success = SignatureCheckerLib.isValidSignatureNowCalldata(
        owner(), SignatureCheckerLib.toEthSignedMessageHash(userOpHash), userOp.signature
    );
    assembly {
        // Returns 0 (valid) or 1 (invalid). Higher bits are validUntil/validAfter (left at 0 = no time bounds).
        validationData := iszero(success)
    }
}

modifier payPrefund(uint256 missingAccountFunds) virtual {
    _;
    assembly {
        if missingAccountFunds {
            // Ignore failure — EntryPoint enforces, not us.
            pop(call(gas(), caller(), missingAccountFunds, codesize(), 0, codesize(), 0))
        }
    }
}
